INSERT INTO recipe (title, parts, description, img, id_recipe_subcategory) VALUES
    ('Cake salé lardons & olives',6,'Préchauffer le four à 180°. Découper les olives en 2 et faire cuire les lardons au micro-onde. Dans un saladier, fouetter les œufs, la farine, la levure, le sel et le poivre. Incorporer petit à petit l’huile et le lait préalablement chauffé. Ajouter le gruyère râpé et mélanger. Enfin, incorporer les olives et les lardons. Bien mélanger. Verser le tout dans un moule et faire cuire pendant 40 minutes.','cake_sale.jpg',(SELECT id FROM recipe_subcategory WHERE label = 'Apéritif')),
    ('Cookies salés',4,'Mélanger le beurre et le parmesan. Ajouter la farine, l’huile d’olive, l’œuf et les épices. Pétrir jusqu’à obtenir un mélange homogène. Incorporer les lardons. Former des boules et les faires cuire 15 minutes à 180 degrés.','cookies_sales.jpg',(SELECT id FROM recipe_subcategory WHERE label = 'Apéritif')),
    ('Ktipiti',4,'Faire cuire les poivrons coupés en deux et la gousse d’ail 25 minutes à 200 degrés. Les laisser 20 minutes supplémentaire dans le four éteint pour que la peau se retire facilement. Une fois épluchés et refroidi, les placer dans le Blender avec tous les autres ingrédients et mixer. Mettre la préparation au frais au moins 1 heure avant de servir.','ktipiti.jpg',(SELECT id FROM recipe_subcategory WHERE label = 'Apéritif')),
